["-- Roles enum + tabla separada (seguridad: nunca en profiles)\nCREATE TYPE public.app_role AS ENUM ('admin', 'artist', 'organizer')","CREATE TABLE public.user_roles (\n  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,\n  role app_role NOT NULL,\n  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n  UNIQUE(user_id, role)\n)","ALTER TABLE public.user_roles ENABLE ROW LEVEL SECURITY","CREATE OR REPLACE FUNCTION public.has_role(_user_id UUID, _role app_role)\nRETURNS BOOLEAN\nLANGUAGE SQL STABLE SECURITY DEFINER SET search_path = public\nAS $$\n  SELECT EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = _user_id AND role = _role)\n$$","CREATE POLICY \"Users can view their own roles\"\n  ON public.user_roles FOR SELECT\n  USING (auth.uid() = user_id)","-- Categorías artísticas\nCREATE TYPE public.artist_category AS ENUM (\n  'musica', 'teatro', 'magia', 'comedia', 'danza', 'dj', 'circo', 'arte', 'foto_video'\n)","CREATE TYPE public.artist_plan AS ENUM ('spark', 'spotlight', 'headliner')","-- Perfiles\nCREATE TABLE public.profiles (\n  id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,\n  slug TEXT UNIQUE,\n  display_name TEXT NOT NULL,\n  category artist_category,\n  city TEXT,\n  bio TEXT,\n  avatar_url TEXT,\n  cover_url TEXT,\n  price_from NUMERIC(10,2),\n  rating NUMERIC(2,1) DEFAULT 0,\n  reviews_count INTEGER NOT NULL DEFAULT 0,\n  plan artist_plan NOT NULL DEFAULT 'spark',\n  is_published BOOLEAN NOT NULL DEFAULT false,\n  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()\n)","ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY","CREATE POLICY \"Public profiles are viewable by everyone\"\n  ON public.profiles FOR SELECT\n  USING (is_published = true OR auth.uid() = id)","CREATE POLICY \"Users can insert their own profile\"\n  ON public.profiles FOR INSERT\n  WITH CHECK (auth.uid() = id)","CREATE POLICY \"Users can update their own profile\"\n  ON public.profiles FOR UPDATE\n  USING (auth.uid() = id)","-- Trigger updated_at\nCREATE OR REPLACE FUNCTION public.handle_updated_at()\nRETURNS TRIGGER LANGUAGE plpgsql AS $$\nBEGIN\n  NEW.updated_at = now();\n  RETURN NEW;\nEND;\n$$","CREATE TRIGGER profiles_updated_at\n  BEFORE UPDATE ON public.profiles\n  FOR EACH ROW EXECUTE FUNCTION public.handle_updated_at()","-- Auto-crear perfil + rol al registrarse\nCREATE OR REPLACE FUNCTION public.handle_new_user()\nRETURNS TRIGGER LANGUAGE plpgsql SECURITY DEFINER SET search_path = public\nAS $$\nBEGIN\n  INSERT INTO public.profiles (id, display_name)\n  VALUES (\n    NEW.id,\n    COALESCE(NEW.raw_user_meta_data->>'display_name', split_part(NEW.email, '@', 1))\n  );\n  INSERT INTO public.user_roles (user_id, role) VALUES (NEW.id, 'artist');\n  RETURN NEW;\nEND;\n$$","CREATE TRIGGER on_auth_user_created\n  AFTER INSERT ON auth.users\n  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user()"]
